#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <string.h>
#include <fcntl.h>

int main() {
    int fd[2];
    pipe(fd); // Create a pipe

    pid_t pid = fork();

    if (pid == -1) {
        // Error occurred
        perror("fork");
        return 1;
    } else if (pid == 0) {
        // Child process
        close(fd[1]); // Close write end in child
        dup2(fd[0], STDIN_FILENO); // Redirect standard input
        close(fd[0]); // Close the pipe file descriptor

        execlp("your_command", "your_command", (char *)0); // Replace with desired command
        perror("execlp");
        return 1;
    } else {
        // Parent process
        close(fd[0]); // Close read end in parent
        dup2(fd[1], STDOUT_FILENO); // Redirect standard output
        close(fd[1]); // Close the pipe file descriptor

        // Optionally, wait for the child to complete
        wait(NULL);

        return 0;
    }
}
```

In this example, replace `"your_command"` with the command you wish to run. This code sets up a pipe, forges a new process, and redirects the standard input and output of the child process to one end of the pipe. The parent process can then read from the other end of the pipe.

